import * as XLSX from 'xlsx';
import dayjs from 'dayjs';
import customParseFormat from 'dayjs/plugin/customParseFormat.js';

dayjs.extend(customParseFormat);

export const processCombinedData = (csvData, excelRaw) => {
  // --- 1. PROCESAR EXCEL (EASY DOCKING) ---
  const workbook = XLSX.read(excelRaw, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const rawMatrix = XLSX.utils.sheet_to_json(sheet, { header: 1 });

  // Buscamos la fila de encabezados (usualmente la 4, índice 3)
  const headers = rawMatrix[3]?.map(h => String(h).trim()) || []; 
  const dataRows = rawMatrix.slice(4);

  const easyDockingClean = dataRows.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  }).filter(item => 
    String(item['TIPO DE OPERACION']).toUpperCase().includes("DESCARGA") && 
    String(item['ACCION']).toLowerCase() === "add"
  );

  // SUMA DE PIEZAS (Excel) - Buscamos 'CANT PAQUETE' o similar
  const totalArribados = easyDockingClean.reduce((acc, curr) => {
    const valor = curr['CANT PAQUETES'] || curr['CANTIDAD'] || 0;
    return acc + (parseFloat(valor) || 0);
  }, 0);

  // --- 2. PROCESAR CSV (TMS) ---
  // CONTAMOS cada registro como 1 pieza
  const totalBipeados = csvData.filter(d => 
    d['Labeling Date Printed'] && String(d['Labeling Date Printed']).trim() !== ""
  ).length;

  // --- 3. CÁLCULOS ---
  const pendientesReales = totalArribados - totalBipeados;
  const eficienciaReal = totalArribados > 0 ? ((totalBipeados / totalArribados) * 100).toFixed(2) : "0.00";

  // --- 4. GRÁFICA (05:00 a 23:00) ---
  const franjas = Array.from({length: 19}, (_, i) => `${(i + 5).toString().padStart(2, '0')}:00`);
  const chartMap = {};
  franjas.forEach(h => chartMap[h] = { hora: h, arribo: 0, bipeo: 0 });

  // Llenar Arribos (Excel)
  easyDockingClean.forEach(row => {
    const fechaRaw = row['Fecha y hor'];
    if (fechaRaw) {
      const hora = dayjs(fechaRaw).format('HH:00');
      if (chartMap[hora]) chartMap[hora].arribo += (parseFloat(row['CANT PAQUETES']) || 0);
    }
  });

  // Llenar Bipeos (CSV)
  csvData.forEach(row => {
    const fechaRaw = row['Labeling Date Printed'];
    if (fechaRaw) {
      const hora = dayjs(fechaRaw, "DD/MM/YYYY HH:mm:ss").format('HH:00');
      if (chartMap[hora]) chartMap[hora].bipeo++;
    }
  });

  return {
    kpis: {
      total: totalBipeados.toLocaleString(), // Muestra bipeados
      pendientes: pendientesReales > 0 ? pendientesReales.toLocaleString() : "0", 
      eficiencia: eficienciaReal // Ahora debería dar un número real
    },
    chartData: Object.values(chartMap),
    tableData: franjas.map(h => ({
        intervalo: h,
        etiquetado: 1000, // Meta base
        piezas: chartMap[h].bipeo,
        usuarios: 12
    }))
  };
};
